/**
 * Response Detection Engine - Production Implementation
 * Generated by Perplexity Labs, enhanced with follow-up research
 *
 * Uses MutationObserver + Multi-strategy detection for robust response completion detection
 * across all AI chat interfaces (Claude, ChatGPT, Gemini, Grok, Perplexity)
 *
 * Detection strategies by reliability:
 * 1. Streaming class removal (95% confidence)
 * 2. Button appearance (90% confidence)
 * 3. Content stability (85% confidence)
 */

// Platform-specific detection strategies
const DETECTION_STRATEGIES = {
  claude: {
    name: 'Claude (Anthropic)',
    selectors: {
      // Multiple selector options - Claude UI changes frequently
      container: '[data-test-render-count], [class*="font-claude-message"], .prose',
      streamingClass: 'result-streaming',
      thinkingIndicator: '[aria-label*="thinking"], [class*="thinking"]',
      completionButtons: 'button[aria-label*="Copy"], button[aria-label*="Retry"]',
      responseContent: '.markdown, [class*="message-content"]'
    },
    detection: {
      primary: 'streamingClass', // Watch for streaming class removal first
      secondary: 'buttonAppearance',
      fallback: 'stabilityCheck',
      timeout: 300000 // 5 minutes for extended thinking
    }
  },
  chatgpt: {
    name: 'ChatGPT (OpenAI)',
    selectors: {
      container: '[data-message-author-role="assistant"]',
      streamingClass: 'result-streaming',
      regenerateButton: 'button[data-testid="regenerate-thread-button"]',
      completionButtons: 'button[data-testid="regenerate-thread-button"], button[aria-label*="Copy"]',
      responseContent: '.markdown'
    },
    detection: {
      primary: 'stabilityCheck', // More reliable than buttonAppearance
      secondary: 'buttonAppearance',
      fallback: 'stabilityCheck',
      timeout: 180000 // 3 minutes for o1 reasoning
    }
  },
  gemini: {
    name: 'Gemini (Google)',
    selectors: {
      container: 'p[data-path-to-node]',
      deepResearchIndicator: '[aria-label*="researching"]',
      progressBar: '.progress-linear',
      responseContent: '.response-container'
    },
    detection: {
      primary: 'stabilityCheck', // Gemini Deep Research needs stability check
      fallback: 'stabilityCheck',
      timeout: 3600000 // 60 minutes for Deep Research
    }
  },
  perplexity: {
    name: 'Perplexity',
    selectors: {
      container: '.prose',
      // Labs working indicator - specific progress element (TODO: get exact selector)
      labsProgressIndicator: '[data-testid="labs-progress"], .labs-working-indicator',
      responseContent: '.answer-container'
    },
    detection: {
      // Use stability check as primary - more reliable for both Labs and Research
      primary: 'stabilityCheck',
      fallback: 'stabilityCheck',
      timeout: 1800000 // 30 minutes for Labs
    }
  },
  grok: {
    name: 'Grok (xAI)',
    selectors: {
      container: 'div.response-content-markdown',
      streamingIndicator: '.streaming',
      responseContent: '.grok-response'
    },
    detection: {
      primary: 'stabilityCheck',
      fallback: 'stabilityCheck',
      timeout: 60000 // 1 minute standard
    }
  }
};

/**
 * Response Detection Engine
 * Detects when AI responses are complete using multiple strategies
 */
export class ResponseDetectionEngine {
  constructor(page, platform, options = {}) {
    this.page = page; // Playwright page object
    this.platform = platform;
    this.config = DETECTION_STRATEGIES[platform];

    if (!this.config) {
      throw new Error(`Unknown platform: ${platform}. Supported: ${Object.keys(DETECTION_STRATEGIES).join(', ')}`);
    }

    this.options = {
      stabilityWindow: options.stabilityWindow || 3000, // 3s no changes = stable (was 2s)
      pollInterval: options.pollInterval || 300, // Check every 300ms (was 500ms)
      initialDelay: options.initialDelay || 1000, // Wait 1s before checking (new)
      debug: options.debug || false,
      ...options
    };

    this.lastContent = '';
    this.lastChangeTime = Date.now();
    this.detectionStartTime = null;
  }

  /**
   * STRATEGY: Streaming Class Removal (95% confidence)
   * Watches for removal of streaming class from container
   * Most reliable for Claude and similar interfaces
   */
  async detectViaStreamingClass() {
    this.log('info', 'Watching for streaming class removal');

    const containerSelector = this.config.selectors.container;
    const streamingClass = this.config.selectors.streamingClass;

    return new Promise(async (resolve, reject) => {
      try {
        // First check if response is already complete
        const containers = await this.page.$$(containerSelector);
        if (containers.length > 0) {
          const lastContainer = containers[containers.length - 1];
          const hasStreamingClass = await lastContainer.evaluate(
            (el, cls) => el.classList.contains(cls),
            streamingClass
          );

          if (!hasStreamingClass) {
            // Already complete - no streaming class present
            const content = await lastContainer.textContent();
            if (content && content.length > 0) {
              this.log('success', 'Response already complete (no streaming class)');
              return resolve({
                method: 'streamingClass',
                confidence: 0.95,
                content: content.trim(),
                detectionTime: Date.now() - this.detectionStartTime,
                note: 'Already complete'
              });
            }
          }
        }

        // Watch for class removal via polling
        const checkStreaming = async () => {
          const containers = await this.page.$$(containerSelector);
          if (containers.length === 0) return false;

          const lastContainer = containers[containers.length - 1];
          const hasStreamingClass = await lastContainer.evaluate(
            (el, cls) => el.classList.contains(cls),
            streamingClass
          );

          if (!hasStreamingClass) {
            const content = await lastContainer.textContent();
            if (content && content.length > 0) {
              return {
                method: 'streamingClass',
                confidence: 0.95,
                content: content.trim(),
                detectionTime: Date.now() - this.detectionStartTime
              };
            }
          }
          return false;
        };

        const pollInterval = setInterval(async () => {
          const result = await checkStreaming();
          if (result) {
            clearInterval(pollInterval);
            clearTimeout(timeoutId);
            this.log('success', 'Streaming class removed - Complete');
            resolve(result);
          }
        }, this.options.pollInterval);

        const timeoutId = setTimeout(() => {
          clearInterval(pollInterval);
          reject(new Error('Streaming class detection timeout'));
        }, 30000); // 30s for streaming detection

      } catch (err) {
        reject(err);
      }
    });
  }

  /**
   * STRATEGY: Content Stability Check (85% confidence)
   * Watches for content to stop changing for stabilityWindow ms
   */
  async detectViaStability() {
    this.log('info', `Starting stability detection (${this.options.stabilityWindow}ms window)`);

    const containerSelector = this.config.selectors.container;

    return new Promise(async (resolve, reject) => {
      const checkStability = async () => {
        try {
          // Get all response containers and use the last one
          const containers = await this.page.$$(containerSelector);
          if (containers.length === 0) {
            this.log('debug', 'No containers found yet');
            return false;
          }

          const lastContainer = containers[containers.length - 1];
          const currentContent = await lastContainer.textContent();
          const now = Date.now();

          if (currentContent !== this.lastContent) {
            // Content changed - reset timer
            this.lastContent = currentContent;
            this.lastChangeTime = now;
            this.log('debug', `Content updated (${currentContent.length} chars)`);
            return false;
          }

          // Check if stable long enough
          const stableTime = now - this.lastChangeTime;
          if (stableTime >= this.options.stabilityWindow && currentContent.length > 0) {
            this.log('success', `Content stable for ${stableTime}ms - Complete`);
            return {
              method: 'stability',
              confidence: 0.85,
              content: currentContent,
              stableTime,
              detectionTime: now - this.detectionStartTime
            };
          }

          return false;
        } catch (err) {
          this.log('debug', `Check error: ${err.message}`);
          return false;
        }
      };

      // Poll for stability
      const pollInterval = setInterval(async () => {
        const result = await checkStability();
        if (result) {
          clearInterval(pollInterval);
          clearTimeout(timeoutId);
          resolve(result);
        }

        // Check timeout
        if (Date.now() - this.detectionStartTime > this.config.detection.timeout) {
          clearInterval(pollInterval);
          clearTimeout(timeoutId);

          // Return whatever we have
          const finalContent = this.lastContent;
          if (finalContent && finalContent.length > 0) {
            resolve({
              method: 'timeout',
              confidence: 0.5,
              content: finalContent,
              detectionTime: Date.now() - this.detectionStartTime
            });
          } else {
            reject(new Error('Detection timeout with no content'));
          }
        }
      }, this.options.pollInterval);

      // Absolute timeout
      const timeoutId = setTimeout(() => {
        clearInterval(pollInterval);
        reject(new Error(`Detection timeout after ${this.config.detection.timeout}ms`));
      }, this.config.detection.timeout + 1000);

      // Initial check
      await checkStability();
    });
  }

  /**
   * STRATEGY: Button Appearance (90% confidence)
   * Watches for Regenerate/Copy buttons to appear
   * Best for ChatGPT which shows clear completion buttons
   */
  async detectViaButtonAppearance() {
    this.log('info', 'Watching for completion button appearance');

    // Use completionButtons if available, fall back to regenerateButton
    const buttonSelector = this.config.selectors.completionButtons || this.config.selectors.regenerateButton;

    return new Promise(async (resolve, reject) => {
      const checkButton = async () => {
        try {
          const buttons = await this.page.$$(buttonSelector);
          for (const button of buttons) {
            // Check visibility using offsetParent (more reliable)
            const isVisible = await button.evaluate(el => el.offsetParent !== null);
            if (isVisible) {
              // Get the response content
              const containers = await this.page.$$(this.config.selectors.container);
              const lastContainer = containers[containers.length - 1];
              const content = lastContainer ? await lastContainer.textContent() : '';

              return {
                method: 'buttonAppearance',
                confidence: 0.90,
                content: content.trim(),
                detectionTime: Date.now() - this.detectionStartTime
              };
            }
          }
          return false;
        } catch (err) {
          this.log('debug', `Button check error: ${err.message}`);
          return false;
        }
      };

      // Wait before checking - avoid false positives from pre-existing buttons
      await new Promise(r => setTimeout(r, this.options.initialDelay));
      this.log('debug', `Waited ${this.options.initialDelay}ms initial delay`);

      const pollInterval = setInterval(async () => {
        const result = await checkButton();
        if (result) {
          clearInterval(pollInterval);
          clearTimeout(timeoutId);
          this.log('success', 'Completion button appeared - Complete');
          resolve(result);
        }
      }, this.options.pollInterval);

      const timeoutId = setTimeout(() => {
        clearInterval(pollInterval);
        this.log('warning', 'Button appearance timeout, falling back to stability');
        // Fall back to stability check
        this.detectViaStability().then(resolve).catch(reject);
      }, 30000); // 30s for button, then fallback
    });
  }

  /**
   * STRATEGY: Labs Completion (92% confidence)
   * Watches for "Working..." indicator to disappear
   * Also handles already-complete responses
   */
  async detectViaLabsCompletion() {
    this.log('info', 'Watching for Labs completion');

    return new Promise(async (resolve, reject) => {
      let wasWorking = false;

      const getContent = async () => {
        const containers = await this.page.$$('.prose');
        const lastContainer = containers[containers.length - 1];
        return lastContainer ? (await lastContainer.textContent()).trim() : '';
      };

      const checkLabs = async () => {
        try {
          // Look for "Working..." text or indicator
          const workingText = await this.page.$('text=Working');
          const isWorking = workingText !== null;

          if (isWorking && !wasWorking) {
            this.log('info', 'Labs is working...');
            wasWorking = true;
          }

          if (wasWorking && !isWorking) {
            // Was working, now done
            const content = await getContent();
            this.log('success', 'Labs completed');
            return {
              method: 'labsCompletion',
              confidence: 0.92,
              content,
              detectionTime: Date.now() - this.detectionStartTime
            };
          }

          return false;
        } catch (err) {
          this.log('debug', `Labs check error: ${err.message}`);
          return false;
        }
      };

      // Check immediately for already-complete response
      const workingText = await this.page.$('text=Working');
      if (!workingText) {
        // No "Working" indicator - check if there's already content
        const content = await getContent();
        if (content && content.length > 100) {
          // Has substantial content and not working - likely already complete
          this.log('success', 'Labs response already complete (no Working indicator)');
          return resolve({
            method: 'labsCompletion',
            confidence: 0.88,
            content,
            detectionTime: Date.now() - this.detectionStartTime,
            note: 'Already complete'
          });
        }
      } else {
        wasWorking = true;
      }

      const pollInterval = setInterval(async () => {
        const result = await checkLabs();
        if (result) {
          clearInterval(pollInterval);
          clearTimeout(timeoutId);
          resolve(result);
        }
      }, 1000); // Check every second for Labs

      const timeoutId = setTimeout(() => {
        clearInterval(pollInterval);
        this.log('warning', 'Labs timeout, falling back to stability');
        this.detectViaStability().then(resolve).catch(reject);
      }, this.config.detection.timeout);
    });
  }

  /**
   * PUBLIC API: Detect Response Completion
   * Automatically selects the best strategy for the platform
   */
  async detectCompletion() {
    this.detectionStartTime = Date.now();
    this.lastContent = '';
    this.lastChangeTime = Date.now();

    this.log('info', `Starting detection for ${this.config.name}`);

    try {
      let result;

      // Select strategy based on platform config
      switch (this.config.detection.primary) {
        case 'streamingClass':
          result = await this.detectViaStreamingClass();
          break;
        case 'buttonAppearance':
          result = await this.detectViaButtonAppearance();
          break;
        case 'labsCompletion':
          result = await this.detectViaLabsCompletion();
          break;
        case 'stabilityCheck':
        default:
          result = await this.detectViaStability();
          break;
      }

      this.log('success', `Detection complete: ${result.method} (${result.confidence * 100}% confidence) in ${result.detectionTime}ms`);
      return result;

    } catch (primaryError) {
      this.log('warning', `Primary detection failed: ${primaryError.message}`);

      // Try secondary strategy if available
      if (this.config.detection.secondary && this.config.detection.secondary !== this.config.detection.primary) {
        this.log('info', `Trying secondary strategy: ${this.config.detection.secondary}`);
        try {
          switch (this.config.detection.secondary) {
            case 'buttonAppearance':
              return await this.detectViaButtonAppearance();
            case 'streamingClass':
              return await this.detectViaStreamingClass();
            case 'stabilityCheck':
            default:
              return await this.detectViaStability();
          }
        } catch (secondaryError) {
          this.log('warning', `Secondary detection failed: ${secondaryError.message}`);
        }
      }

      // Try fallback (stability check)
      if (this.config.detection.fallback === 'stabilityCheck') {
        this.log('info', 'Trying fallback stability check...');
        try {
          return await this.detectViaStability();
        } catch (fallbackError) {
          this.log('error', `Fallback also failed: ${fallbackError.message}`);
          throw fallbackError;
        }
      }

      throw primaryError;
    }
  }

  /**
   * Utility: Logging
   */
  log(level, message) {
    if (this.options.debug || level === 'error' || level === 'warning' || level === 'success') {
      const timestamp = new Date().toISOString().split('T')[1].split('.')[0];
      const prefix = {
        debug: '  ',
        info: '  ',
        warning: '⚠️',
        error: '❌',
        success: '✓'
      }[level] || '  ';
      console.log(`  [${timestamp}] ${prefix} [${this.platform}] ${message}`);
    }
  }
}

// Export strategies for inspection
export { DETECTION_STRATEGIES };

export default ResponseDetectionEngine;
